var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"......리!","JPN":"……ベ！","ENG":"... ri!","TWN":"……麗！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"......이유리!","JPN":"……カスカベ！","ENG":"... Lee Yuri!","TWN":"……李悠麗！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"야 임마! 정신 차려!","JPN":"おい！　しっかりしろ！","ENG":"Hey! Come on! Get up!","TWN":"喂！小子！振作點啊！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FIRE_LOOP"},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"방금......","JPN":"うう……","ENG":"What...","TWN":"剛才……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장...... 이게 지금...... 뭐가 어떻게 된 거야?","JPN":"隊長……これは……どうなってるんだ？","ENG":"What just... happened, Captain?","TWN":"隊長……這到底是……怎麼回事？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"닥치고 차에 타기나 해!","JPN":"いいから車に乗れ！","ENG":"Shut up and just get in the car!","TWN":"別說了，先上車！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"불길이 더 거세지고 있다고.","JPN":"火の勢いが強くなってきたぞ！","ENG":"The fire's getting stronger.","TWN":"火勢越來越猛了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"당장 도망치지 않으면 우리 둘 다 사이 좋게 여기서 타 죽을 거다!","JPN":"今すぐ逃げないと俺たち二人仲良くここで焼死するぞ！","ENG":"If we don't get away right now, we'll both become barbecue here!","TWN":"如果不趕快離開，我們兩個人會被活活燒死！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"제길, 시동 좀 걸려!","JPN":"くそっ、エンジンがかからない！","ENG":"Dammit, start already!","TWN":"該死，快動起來！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_06"},{"id":"L20_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"됐어!","JPN":"よし！　できた！","ENG":"There!","TWN":"好了！"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"지금 어디로 가는 거야......? 지훈은?","JPN":"今どこに向かってるんだ……？　ゴトウは？","ENG":"Where are we going? And where's Jihoon?","TWN":"現在要去哪裡……？智勳呢？"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그런 폭발에 휘말리면, 평범한 사람은 당연히 죽어.","JPN":"あんな爆発に巻き込まれたら、普通の人間は当然死ぬ。","ENG":"There's no way any ordinary man could survive a blast like that.","TWN":"被捲入那麼大的爆炸，普通人肯定會沒命。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그럼...... 그 자식은? 그 괴물 같은 놈도 죽은 거야?","JPN":"じゃあ……あいつは？　あの化け物みたいな奴も死んだのか？","ENG":"Then what about that bastard? Did that monster die too?","TWN":"那……那傢伙呢？那個怪物也死了嗎？"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......몰라. 시체를 확인한 건 아니니까.","JPN":"……わからない。死体を確かめたわけじゃないからな。","ENG":"I wouldn't know... I never saw the body.","TWN":"……不知道，我沒有去確認屍體。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만...... 아마도 살아 있겠지.","JPN":"だが……おそらく生きているだろう。","ENG":"But... I doubt that he's dead.","TWN":"不過……可能還活著吧。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"카운터란 건, 그런 놈들이니까.","JPN":"カウンターというのは、そういう存在だから。","ENG":"It takes a lot to kill a Counter, after all.","TWN":"所謂制裁者，都是如此。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......제기랄!","JPN":"……クソ！","ENG":"Darn it!","TWN":"可惡！"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"생사를 확인하지 못한 건 두 사람 다 마찬가지잖아?","JPN":"生死を確認できなかったのは二人とも同じだろ！","ENG":"But we haven't found Jihoon's body either!","TWN":"兩個人不都是生死未卜嗎？"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그런데 어째서 누군 죽었다고 단언하고, 그 쓰레기는 살아 있을 거라고 말하는 건데!","JPN":"なのにどうしてあいつは死んだ、あのクズは生きていると断言するんだ！","ENG":"How can you be so sure that Jihoon's dead when you think that monster is alive?!","TWN":"你憑什麼斷言智勳死了，那個垃圾卻還活著！"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"왜! 놈들은 그런 힘을 가지고! 남의 인생을 망가트리면서도!!","JPN":"なんで！　奴らはあんな力を持って！　他人の人生をぶち壊すくせに！！","ENG":"It's not fair... They use their power to ruin other people's lives...","TWN":"為什麼！他們擁有那種力量！破壞別人的生活！"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"왜...... 끈질기게 살아남는 거냐고......","JPN":"なんで……しぶとく生き残るんだよ……","ENG":"How come they're the ones that get to survive?","TWN":"卻還能……苟延殘喘……"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"......뭔 쓸데없는 걸 묻고 있는 거야?","JPN":"……そんなことを聞いて意味があるのか？","ENG":"Why are you asking such a stupid question?","TWN":"……問這些沒用的東西幹什麼？"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그딴 건 처음부터 알고 있었잖아.","JPN":"最初からわかっていたんだろ。","ENG":"You already knew the answer from the beginning.","TWN":"妳明明一開始就知道的。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이 세상은 하나부터 열까지 불공평하기 짝이 없다는 걸......","JPN":"この世は何もかも、不公平であるということを……","ENG":"This world is unfair at every turn.","TWN":"這個世界充滿了不公平……"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"하지만......","JPN":"でも……","ENG":"But...","TWN":"但是……"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"불평은 그만해! 헛소리 할 기운이 있으면 살아남을 걱정이나 하라고.","JPN":"そこまでにしろ！　文句を言う元気があるなら、どう生き残るかを心配しろ。","ENG":"Stop complaining! Just focus on surviving if you've got that kind of energy.","TWN":"別憤憤不平了！有閒功夫說這些，不如想想接下來怎麼保命吧。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리, 내 말 잘 들어.","JPN":"カスカベ、俺の話をよく聞け。","ENG":"Listen closely, Yuri.","TWN":"李悠麗，妳聽著。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"넌 우리와 같은 민병대야.","JPN":"お前は俺たちと同じ民兵隊だ。","ENG":"You are part of the Militia, just like us.","TWN":"妳和我們一樣，都是民兵隊。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"카운터 범죄자를 증오하고, 복수를 위해 싸우지. 그 사실은 변하지 않아.","JPN":"カウンター犯罪者を憎み、復讐のために戦う。その事実は変わらない。","ENG":"We hate criminal Counters and we fight for revenge. Nothing can change that.","TWN":"我們都憎恨制裁者犯罪者，都為了復仇而戰。這個事實不會改變。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만, 너에겐 우리와 다른 결정적인 차이가 있어.","JPN":"しかし、お前と俺たちには決定的な違いがある。","ENG":"But there's one decisive difference between you and the rest of us.","TWN":"但是，妳和我們有一點根本性的不同之處。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"그게...... 갑자기 무슨 소리야?","JPN":"それは……いきなりどういうこと？","ENG":"What are you even talking about?","TWN":"你……在說什麼？"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"이제 와서 또 신참 취급이라도 하려는 거야?","JPN":"今更また新人扱いでもする気か？","ENG":"You want to start treating me like a rookie again?","TWN":"又要把我當新人對待嗎？"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래, 원래대로라면 넌 고작해야 총알받이로나 쓰일 애송이였지.","JPN":"そうさ、本来ならお前はせいぜい弾除けに使われるだけの若造だった。","ENG":"Yes, you were just a rookie, who was supposed to be nothing more than a meat shield.","TWN":"沒錯，我原本以為，憑妳的本事，頂多只能成為戰場的炮灰而已。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"민병대에 들어오기 전까지 전투 훈련은 고사하고 총도 잡아 본 적 없었으니까.","JPN":"民兵隊に入るまで戦闘訓練どころか、銃を握ったことすらなかったからだ。","ENG":"Until you joined the Militia, you had never held a gun in your life, let alone received any combat training.","TWN":"在加入民兵隊之前，別說是戰鬥訓練，妳甚至連槍都沒碰過。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 다른 사람들이 다 죽어 나자빠지는 동안에도...... 넌 지금까지 살아남았다.","JPN":"しかし他の奴らがくたばっていく中……お前は今まで生き残れた。","ENG":"But even as everyone else got killed off... you've managed to survive.","TWN":"但是在其他人接連喪命時……妳卻活到了現在。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그게 네 실력이나 운 때문이었다고 생각하진 않겠지?","JPN":"それがお前の実力や運のおかげだと思ってないよな？","ENG":"You don't think that was thanks to sheer luck or your skills, do you?","TWN":"妳不會以為妳是憑藉實力或運氣活到今天的吧？"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"생색이라도 내고 싶은 거야? 지켜줘서 고맙다는 말이라도 해 줄까?","JPN":"ずいぶん恩着せがましいな。守ってくれてありがとう、これでいいか？","ENG":"So what? You want to rub it in my face? Am I supposed to thank you for keeping me alive?","TWN":"你是希望我向你道謝嗎？希望我感謝你保護我？"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그럴리가, 나나 지훈이 놈이나 널 지켜 준 적 따윈 단 한 번도 없어.","JPN":"いや、俺もゴトウも、お前を守ったことなんて一度もない。","ENG":"Of course not. Neither Jihoon nor I ever tried to protect you. Not once.","TWN":"當然不是，無論是我還是智勳，從來沒有試圖保護過妳。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"너도 알고 있을 거야.","JPN":"お前もわかっているはずだ。","ENG":"I'm sure you know by now...","TWN":"妳應該也知道吧。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이젠 스스로 인정하고 받아들여야만 할 때라는 걸.","JPN":"みずから認め、受け入れなければならない時だということを。","ENG":"that it's time to accept the truth about yourself.","TWN":"是時候承認和接受了。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"아마도...... 더는 미룰 시간이 없을 테니까.","JPN":"おそらく……これ以上先送りにする時間はないからな。","ENG":"It's likely... that you won't have much time to spare.","TWN":"時間已經……所剩無幾了。"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"넌......!","JPN":"お前は……！","ENG":"You're—","TWN":"妳是……！"},"stage":{"bg":"SS_MILITIA_01","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"으윽......","JPN":"ううっ……","ENG":"Hngh...","TWN":"呃……"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"대장...... 괜찮아?","JPN":"隊長……大丈夫？","ENG":"Are you alright, Captain?","TWN":"隊長......沒事吧？"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"죽은 거...... 아니지?","JPN":"死んで……ないよね？","ENG":"You're not dead... are you?","TWN":"不會是……死了吧？"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":null,"text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_Q","text":{"KOREA":"뭐야, 겨우 여기까지밖에 도망치지 못한 거냐.","JPN":"なんだ、ここまでしか逃げられなかったのか。","ENG":"Hah, is this as far as you've got?","TWN":"怎麼，還沒有逃遠嘛。"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_Q","text":{"KOREA":"기대해도 좋아. 쉽게 죽여 주진 않을 테니까.","JPN":"期待してもいいぞ。簡単に殺してなんてやらないからな。","ENG":"Don't worry. I won't kill you... just yet.","TWN":"等著瞧，我不會輕易死掉的。"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MATCHMAN_NPC_NULL_Q","text":{"KOREA":"아주 길고...... 즐거운 밤이 될 거다. 이 쥐새끼들아.","JPN":"とても長い……そして楽しい夜になるぞ、このドブネズミども。","ENG":"It's going to be a very long and exciting night, you rats.","TWN":"這將會是一個漫長……且愉快的夜晚，你們這些臭老鼠。"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"black","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"어째서 희생을 막기 위해 사람은, 또 누군가를 잃는 희생을 해야만 하는 걸까.","JPN":"人はどうして、犠牲を防ぐために、また他の誰かを犠牲にしなければならないのだろうか。","ENG":"Why does it cost someone's life to prevent the others' deaths?","TWN":"難道為了挽救一個人，只能犧牲另一個人嗎？"},"stage":{"bg":"black","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_S_MILITIA_YURI_IN_TRAILER_1"},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"우리의 계획은...... 대체 어디서부터 잘못됐던 걸까.","JPN":"私たちの計画はいったいどこから間違っていたのだろうか。","ENG":"Where did our plans go wrong?","TWN":"我們的計畫……到底是從哪裡開始出了差錯。"},"stage":{"bg":"black","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_S_MILITIA_YURI_IN_TRAILER_2"},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"내가...... 처음부터 아무것도 시도하지 않았더라면......","JPN":"私が……最初から何もしなければ……","ENG":"What if... I never tried anything at all in the first place?","TWN":"如果我……一開始什麼都不去嘗試……"},"stage":{"bg":"black","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_S_MILITIA_YURI_IN_TRAILER_3"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"과거를 묻어 둔 채 평범한 사람처럼 살았더라면......","JPN":"過去を葬ったまま、平凡な人生を過ごしていたなら……","ENG":"What if I just put my past behind me, and led an ordinary life?","TWN":"把過去的事埋在心裡，度過平凡的生活……"},"stage":{"bg":"black","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_S_MILITIA_YURI_IN_TRAILER_4"},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"어쩌면......","JPN":"もしかしたら……","ENG":"Then maybe...","TWN":"也許……"},"stage":{"bg":"black","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"voice":"AB_UI_UNIT_VOICE_NKM_UNIT_S_MILITIA_YURI_IN_TRAILER_5"}]`);export{e as default};